// Determine 'since' date from cursor or default 7 days
const cursorRows = $input.all();
let since;
if (cursorRows.length > 0 && Array.isArray(cursorRows[0].json) && cursorRows[0].json.length > 0) {
  since = cursorRows[0].json[0].cursor_value;
} else if (cursorRows.length > 0 && cursorRows[0].json?.cursor_value) {
  since = cursorRows[0].json.cursor_value;
} else {
  const d = new Date(); d.setDate(d.getDate() - 7);
  since = d.toISOString().split('T')[0];
}
console.log(`Sync since: ${since}`);
return [{ json: { since, page: 1, allShipments: [], done: false } }];

const response = $input.first().json;
const body = response.body || response;
const headers = response.headers || {};
const shipments = body.shipments || [];
const totalPages = body.pages || 1;
const total = body.total || 0;
const prev = $('More Pages?').first().json;
const currentPage = prev.page;
const since = prev.since;
const prevShipments = prev.allShipments || [];
const allShipments = prevShipments.concat(shipments);

const rateLimitRemaining = parseInt(headers['x-rate-limit-remaining'] || '40');
const needsPause = rateLimitRemaining <= 2;
const done = currentPage >= totalPages || shipments.length === 0;

console.log(`Page ${currentPage}/${totalPages}: ${shipments.length} shipments (accumulated: ${allShipments.length}/${total})`);

return [{ json: { since, page: currentPage + 1, allShipments, totalPages, total, done, needsPause, rateLimitRemaining } }];

// ═══════════════════════════════════════════════════════════════
// Process all accumulated ShipStation shipments → Supabase
// Handles: order lookup, existing shipment detection, enrich vs create
// ═══════════════════════════════════════════════════════════════

const input = $input.first().json;
const shipments = input.allShipments || [];
const since = input.since;

const SUPA_URL = process.env.SUPABASE_URL;
const SUPA_KEY = process.env.SUPABASE_SERVICE_ROLE_KEY;

const CARRIER_NAMES = {
  stamps_com: 'USPS (Stamps.com)', usps: 'USPS', ups: 'UPS', ups_walleted: 'UPS',
  fedex: 'FedEx', amazon_buy_shipping: 'Amazon Buy Shipping',
  dhl_express: 'DHL Express', ontrac: 'OnTrac'
};

const stats = { fetched: shipments.length, created: 0, enriched: 0, skipped: 0, errors: 0, totalSpend: 0 };

async function supaGet(path) {
  const res = await fetch(`${SUPA_URL}/rest/v1/${path}`, {
    headers: { apikey: SUPA_KEY, Authorization: `Bearer ${SUPA_KEY}` }
  });
  if (!res.ok) throw new Error(`GET ${res.status}`);
  return res.json();
}

async function supaPatch(table, id, data) {
  const res = await fetch(`${SUPA_URL}/rest/v1/${table}?id=eq.${id}`, {
    method: 'PATCH',
    headers: { apikey: SUPA_KEY, Authorization: `Bearer ${SUPA_KEY}`,
      'Content-Type': 'application/json', Prefer: 'return=minimal' },
    body: JSON.stringify(data)
  });
  if (!res.ok) throw new Error(`PATCH ${res.status}: ${await res.text()}`);
}

async function supaPost(table, data) {
  const res = await fetch(`${SUPA_URL}/rest/v1/${table}`, {
    method: 'POST',
    headers: { apikey: SUPA_KEY, Authorization: `Bearer ${SUPA_KEY}`,
      'Content-Type': 'application/json', Prefer: 'return=representation' },
    body: JSON.stringify(data)
  });
  if (!res.ok) throw new Error(`POST ${table} ${res.status}: ${await res.text()}`);
  return res.json();
}

// Caches
const orderCache = {};
const trackingCache = {};

async function findOrder(orderNumber) {
  if (!orderNumber) return null;
  if (orderCache[orderNumber] !== undefined) return orderCache[orderNumber];
  try {
    const rows = await supaGet(`orders?order_number=eq.${encodeURIComponent(orderNumber)}&select=id&limit=1`);
    orderCache[orderNumber] = rows?.[0]?.id || null;
  } catch { orderCache[orderNumber] = null; }
  return orderCache[orderNumber];
}

async function findExisting(tracking, ssId, orderId) {
  if (tracking) {
    if (trackingCache[tracking] !== undefined) return trackingCache[tracking];
    try {
      const rows = await supaGet(`shipments?tracking_number=eq.${encodeURIComponent(tracking)}&select=id,data_source,external_ids&limit=1`);
      if (rows?.[0]) { trackingCache[tracking] = rows[0]; return rows[0]; }
    } catch {}
  }
  if (ssId) {
    try {
      const rows = await supaGet(`shipments?external_ids->>shipstation=eq.${ssId}&select=id,data_source,external_ids&limit=1`);
      if (rows?.[0]) return rows[0];
    } catch {}
  }
  if (orderId) {
    try {
      const rows = await supaGet(`shipments?order_id=eq.${orderId}&select=id,data_source,tracking_number,external_ids&limit=5`);
      if (rows?.length) {
        return rows.find(s => s.tracking_number === tracking) || rows.find(s => !s.tracking_number) || rows[0];
      }
    } catch {}
  }
  return null;
}

for (let i = 0; i < shipments.length; i++) {
  const ss = shipments[i];
  const ssId = String(ss.shipmentId);
  const orderNumber = ss.orderNumber;
  const tracking = ss.trackingNumber;
  const cost = ss.shipmentCost ?? null;
  const carrier = ss.carrierCode || null;
  const service = ss.serviceCode || null;

  if (i % 100 === 0) console.log(`Processing ${i + 1}/${shipments.length}: ${orderNumber}`);

  try {
    const orderId = await findOrder(orderNumber);
    const existing = await findExisting(tracking, ssId, orderId);

    if (existing) {
      const mergedIds = { ...(existing.external_ids || {}), shipstation: ssId };
      const patch = { external_ids: mergedIds };
      if (tracking) patch.tracking_number = tracking;
      if (cost != null) {
        patch.label_cost = cost;
        patch.insurance_cost = ss.insuranceCost || 0;
        patch.total_cost = +(cost + (ss.insuranceCost || 0)).toFixed(2);
      }
      if (carrier) { patch.carrier_name = CARRIER_NAMES[carrier] || carrier; patch.carrier_code = carrier; }
      if (service) patch.carrier_service = service;
      if (ss.shipDate) patch.shipped_at = ss.shipDate + 'T00:00:00Z';
      if (tracking) patch.status = 'in_transit';

      await supaPatch('shipments', existing.id, patch);
      stats.enriched++;
      if (cost != null) stats.totalSpend += cost;

    } else if (orderId) {
      const dims = ss.dimensions || {};
      const weightOz = ss.weight?.units === 'ounces' ? ss.weight?.value :
                       ss.weight?.units === 'pounds' ? (ss.weight?.value || 0) * 16 :
                       ss.weight?.value || null;

      await supaPost('shipments', {
        order_id: orderId,
        label_source: 'shipstation',
        data_source: 'shipstation',
        status: ss.voided ? 'cancelled' : (tracking ? 'in_transit' : 'label_printed'),
        carrier_name: CARRIER_NAMES[carrier] || carrier,
        carrier_code: carrier,
        carrier_service: service,
        service_code: service,
        tracking_number: tracking,
        label_created_at: ss.createDate,
        shipped_at: ss.shipDate ? ss.shipDate + 'T00:00:00Z' : null,
        label_cost: cost,
        insurance_cost: ss.insuranceCost || 0,
        total_cost: cost != null ? +(cost + (ss.insuranceCost || 0)).toFixed(2) : null,
        weight_oz: weightOz,
        length_in: dims.length || null,
        width_in: dims.width || null,
        height_in: dims.height || null,
        is_voided: ss.voided || false,
        voided_at: ss.voidDate || null,
        confirmation_type: ss.confirmation || null,
        external_ids: { shipstation: ssId }
      });
      stats.created++;
      if (cost != null) stats.totalSpend += cost;

    } else {
      stats.skipped++;
    }
  } catch (e) {
    stats.errors++;
    if (stats.errors <= 10) console.log(`Error ${ssId}: ${e.message}`);
  }
}

console.log('\n════════════════════════════════');
console.log(`Sync complete!`);
console.log(`  Fetched:    ${stats.fetched}`);
console.log(`  Created:    ${stats.created}`);
console.log(`  Enriched:   ${stats.enriched}`);
console.log(`  Skipped:    ${stats.skipped}`);
console.log(`  Errors:     ${stats.errors}`);
console.log(`  Spend:      $${stats.totalSpend.toFixed(2)}`);

return [{ json: { message: 'Sync complete', stats, since } }];
